import argparse
import ssl
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=config)
    admin_client.create_topics(new_topics=[topic], validate_only=False)

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Script')
    parser.add_argument('--bootstrap-server', required=True, help='Kafka bootstrap server')
    parser.add_argument('--topic-name', required=True, help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--config', nargs='*', help='Topic configuration in key=value format', default=[])

    args = parser.parse_args()

    config_dict = dict(config.split('=') for config in args.config)

    ssl_context = ssl.create_default_context()
    ssl_context.load_cert_chain(certfile='path/to/certfile', keyfile='path/to/keyfile')
    ssl_context.load_verify_locations(cafile='path/to/cafile')

    admin_client = KafkaAdminClient(
        bootstrap_servers=args.bootstrap_server,
        security_protocol='SSL',
        ssl_context=ssl_context
    )

    create_topic(admin_client, args.topic_name, args.partitions, args.replication_factor, config_dict)

if __name__ == '__main__':
    main()